mapper.select:
select t.Task_ID as taskId, t.Teacher_ID as teacherId, t.Course_ID as courseId, t.Class_ID as classId, t.Task_State as taskState, te.Teacher_Name as teacherName, c.Course_Name as courseName, cl.Class_Name as className from teaching_task t left join teacher te on t.Teacher_ID = te.Teacher_ID left join course c on t.Course_ID = c.Course_ID left join class cl on t.Class_ID = cl.Class_ID
and t.Teacher_ID = #{teacherId}
and t.Course_ID = #{courseId}
and t.Class_ID = #{classId}
and t.Task_State = #{taskState}
order by t.Task_ID limit #{offset}, #{pageSize}

select count(*)
from teaching_task t


        and t.Teacher_ID = #{teacherId}


        and t.Course_ID = #{courseId}


        and t.Class_ID = #{classId}


        and t.Task_State = #{taskState}
